
"use client"

import { BottomNav } from "@/components/layout/bottom-nav";
import { Button } from "@/components/ui/button";
import { Card } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import { Settings, Share2, PlusCircle, Zap, MapPin, Loader2 } from "lucide-react";
import Image from "next/image";
import { useUser, useDoc, useFirestore, useMemoFirebase } from "@/firebase";
import { doc } from "firebase/firestore";

export default function ProfilePage() {
  const { user, isUserLoading } = useUser();
  const db = useFirestore();

  const profileRef = useMemoFirebase(() => {
    if (!user || !db) return null;
    return doc(db, "users", user.uid);
  }, [user, db]);

  const { data: profile, isLoading: isProfileLoading } = useDoc(profileRef);

  if (isUserLoading || isProfileLoading) {
    return (
      <div className="flex flex-col min-h-screen bg-background items-center justify-center">
        <Loader2 className="w-10 h-10 text-accent animate-spin" />
      </div>
    );
  }

  return (
    <div className="flex flex-col min-h-screen bg-background text-foreground pb-24">
      {/* Header / Cover Area */}
      <div className="relative h-48 w-full overflow-hidden">
        <Image 
          src="https://picsum.photos/seed/car-cover/1200/400" 
          alt="Cover e Makinës" 
          fill 
          className="object-cover opacity-40 grayscale blur-sm"
        />
        <div className="absolute inset-0 bg-gradient-to-t from-background to-transparent" />
        <div className="absolute top-6 right-6 flex gap-2">
          <Button size="icon" variant="outline" className="rounded-xl glass border-white/10 w-10 h-10"><Share2 className="w-4 h-4" /></Button>
          <Button size="icon" variant="outline" className="rounded-xl glass border-white/10 w-10 h-10"><Settings className="w-4 h-4" /></Button>
        </div>
      </div>

      {/* Profile Info Overlay */}
      <div className="px-6 -mt-16 relative z-10 flex flex-col items-center text-center">
        <Avatar className="w-32 h-32 rounded-3xl border-4 border-background shadow-2xl overflow-hidden mb-4">
          <AvatarImage src={profile?.profilePhotoUrl || `https://picsum.photos/seed/${user?.uid}/200/200`} />
          <AvatarFallback>{profile?.username?.charAt(0) || user?.email?.charAt(0)}</AvatarFallback>
        </Avatar>
        <div className="space-y-1">
          <h1 className="text-2xl font-black italic tracking-tighter uppercase">
            {profile?.username?.split(' ')[0] || 'Shofer'}<span className="text-accent"> {profile?.username?.split(' ')[1] || 'Elitë'}</span>
          </h1>
          <div className="flex items-center justify-center gap-2">
            <Badge variant="outline" className="bg-accent/10 border-accent/20 text-accent font-bold">
              {profile?.isPremium ? 'PREMIUM' : 'SHOFER KOSOVAR'}
            </Badge>
            <div className="flex items-center gap-1 text-[10px] font-bold text-muted-foreground uppercase">
              <MapPin className="w-3 h-3" />
              {profile?.city || 'Kosovë'}
            </div>
          </div>
        </div>

        <div className="flex gap-4 w-full mt-6">
          <div className="flex-1 glass rounded-2xl p-3 border-white/5">
            <p className="text-[10px] font-black text-muted-foreground uppercase">Ndjekës</p>
            <p className="text-lg font-black italic">0</p>
          </div>
          <div className="flex-1 glass rounded-2xl p-3 border-white/5">
            <p className="text-[10px] font-black text-muted-foreground uppercase">Gara</p>
            <p className="text-lg font-black italic">0</p>
          </div>
          <div className="flex-1 glass rounded-2xl p-3 border-white/5">
            <p className="text-[10px] font-black text-muted-foreground uppercase">Rangu</p>
            <p className="text-lg font-black italic text-accent">--</p>
          </div>
        </div>
      </div>

      {/* Car Profile Section */}
      <div className="px-6 mt-8 space-y-4">
        <div className="flex items-center justify-between">
          <h2 className="text-sm font-black uppercase tracking-widest text-muted-foreground">GARAHA IME</h2>
          <Button variant="ghost" size="sm" className="text-accent hover:bg-accent/10 flex items-center gap-1 font-bold">
            <PlusCircle className="w-4 h-4" />
            Shto Makinë
          </Button>
        </div>

        <Card className="glass border-accent/20 overflow-hidden relative group">
          <div className="relative h-48 w-full">
            <Image 
              src="https://picsum.photos/seed/bmw-garage/600/400" 
              alt="Profili i Makinës" 
              fill 
              className="object-cover"
            />
            <div className="absolute inset-0 bg-gradient-to-t from-background/90 via-transparent to-transparent" />
            <div className="absolute bottom-4 left-4">
              <h3 className="text-xl font-black italic text-white uppercase">{profile?.carBrand || 'Pa specifikuar'} {profile?.carModel || ''}</h3>
              <p className="text-[10px] font-bold text-muted-foreground uppercase">
                {profile?.horsepower || 0}HP • {profile?.modifications || 'Stock'}
              </p>
            </div>
            <div className="absolute top-4 right-4">
              <Badge className="bg-accent text-background font-black italic">KRYESORE</Badge>
            </div>
          </div>
          <div className="p-4 grid grid-cols-3 gap-2 bg-white/5">
            <div className="text-center">
              <p className="text-[9px] font-bold text-muted-foreground uppercase">0-100 Max</p>
              <p className="text-sm font-black italic text-accent">--</p>
            </div>
            <div className="text-center border-x border-white/10">
              <p className="text-[9px] font-bold text-muted-foreground uppercase">100-200 Max</p>
              <p className="text-sm font-black italic text-accent">--</p>
            </div>
            <div className="text-center">
              <p className="text-[9px] font-bold text-muted-foreground uppercase">Shpejtësia Max</p>
              <p className="text-sm font-black italic text-accent">--</p>
            </div>
          </div>
        </Card>

        {/* Modifications List */}
        <div className="glass rounded-2xl p-4 border-white/5 space-y-3">
          <h4 className="text-[10px] font-black text-accent uppercase tracking-widest flex items-center gap-2">
            <Zap className="w-3 h-3" />
            MODIFIKIMET AKTUALE
          </h4>
          <ul className="grid grid-cols-1 gap-2">
            <li className="flex items-center gap-2 text-xs font-medium text-muted-foreground bg-white/5 p-2 rounded-lg border border-white/5">
              <div className="w-1.5 h-1.5 rounded-full bg-accent" />
              {profile?.modifications || 'Nuk ka modifikime të listuara'}
            </li>
          </ul>
        </div>
      </div>

      <BottomNav />
    </div>
  );
}
